import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import LoadingSpinner from '../shared/LoadingSpinner';
import AlertMessage from '../shared/AlertMessage';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const CertificateViewerPage = () => {
  const { t } = useTranslation();
  const { id, templateName } = useParams();
  const [certificateSvgUrl, setCertificateSvgUrl] = useState(null);
  const [certificate, setCertificate] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // SVG转base64工具
  async function svgUrlToBase64(url) {
    const response = await fetch(url);
    const text = await response.text();
    // encodeURIComponent后替换特殊字符，保证兼容性
    const encoded = encodeURIComponent(text).replace(/'/g, '%27').replace(/"/g, '%22');
    return `data:image/svg+xml;utf8,${encoded}`;
  }

  // 英文日期格式
  function formatDateEn(dateString) {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
  }

  // SVG素材base64
  const sealBase64 = `data:image/svg+xml;utf8,${encodeURIComponent(`
<svg width="180" height="180" viewBox="0 0 600 600" xmlns="http://www.w3.org/2000/svg">
  <ellipse cx="300" cy="300" rx="290" ry="280" fill="#D4A017"/>
  <ellipse cx="320" cy="320" rx="270" ry="260" fill="#D4A017" opacity="0.2"/>
  <defs>
    <path id="sealTextPath" d="M300,300 m-220,0 a220,220 0 1,1 440,0 a220,220 0 1,1 -440,0"/>
  </defs>
  <text font-family="Times New Roman" font-size="32" fill="#D4A017" letter-spacing="2">
    <textPath xlink:href="#sealTextPath" startOffset="0">
      STRATFORD INTERNATIONAL UNIVERSITY
    </textPath>
  </text>
  <g transform="translate(300,300) scale(1.2)">
    <polygon points="0,-80 60,-40 60,60 -60,60 -60,-40" fill="#003087" stroke="#D4A017" stroke-width="8"/>
    <rect x="-25" y="-20" width="50" height="30" fill="#FFF" stroke="#D4A017" stroke-width="3"/>
    <rect x="-10" y="-10" width="20" height="20" fill="#003087"/>
    <rect x="-2" y="-30" width="4" height="20" fill="#D4A017"/>
    <polygon points="0,-40 8,-20 -8,-20" fill="#D4A017"/>
  </g>
</svg>
`)}`;

  // 生成SVG字符串
  async function getCertificateSVG(cert) {
    if (!cert) return '';
    const origin = window.location.origin;
    const presidentSign = await svgUrlToBase64(`${origin}/images/signatures/president.svg`);
    const directorSign = await svgUrlToBase64(`${origin}/images/signatures/director.svg`);
    const logoImg = await svgUrlToBase64(`${origin}/images/logo/logo.svg`);
    
    // 使用高质量的证书模板
    let svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg width="1200" height="900" xmlns="http://www.w3.org/2000/svg">
  <!-- 背景 -->
  <rect width="1200" height="900" fill="#FFFDF0" />
  
  <!-- 双层边框 - 黄金色 -->
  <rect x="30" y="30" width="1140" height="840" fill="none" stroke="#D4A017" stroke-width="8"/>
  <rect x="50" y="50" width="1100" height="800" fill="none" stroke="#D4A017" stroke-width="3"/>
  
  <!-- 图案背景 -->
  <defs>
    <pattern id="grid" width="50" height="50" patternUnits="userSpaceOnUse">
      <rect x="0" y="0" width="50" height="50" fill="none" stroke="#FFF5E1" stroke-width="1" opacity="0.2"/>
    </pattern>
  </defs>
  <rect width="1200" height="900" fill="url(#grid)" opacity="0.3" />
  
  <!-- 顶部校徽 -->
  <circle cx="600" cy="150" r="80" fill="#003087" stroke="#D4A017" stroke-width="3" />
  <circle cx="600" cy="150" r="70" fill="#003087" stroke="#D4A017" stroke-width="1" />
  <text x="600" y="175" font-family="Times New Roman, serif" font-size="80" font-weight="bold" text-anchor="middle" fill="#D4A017">SIU</text>
  
  <!-- 大学名称 -->
  <text x="600" y="280" font-family="Times New Roman, serif" font-size="40" font-weight="bold" text-anchor="middle" fill="#003087">${t('certificate.universityName')}</text>
  
  <!-- 证书标题 -->
  <text x="600" y="350" font-family="Times New Roman, serif" font-size="50" font-weight="bold" text-anchor="middle" fill="#D4A017">${t('certificate.completionTitle')}</text>
  
  <!-- 证书文本 -->
  <text x="600" y="420" font-family="Times New Roman, serif" font-size="24" text-anchor="middle" fill="#000000">${t('certificate.certifiesText')}</text>
  
  <!-- 接收者姓名 -->
  <text x="600" y="500" font-family="Times New Roman, serif" font-size="40" font-style="italic" font-weight="bold" text-anchor="middle" fill="#000000">${cert.recipientName || cert.name || ''}</text>
  
  <!-- 学位文本 -->
  <text x="600" y="570" font-family="Times New Roman, serif" font-size="24" text-anchor="middle" fill="#000000">${t('certificate.requirementsText')}</text>
  
  <!-- 学位名称 -->
  <text x="600" y="640" font-family="Times New Roman, serif" font-size="36" font-weight="bold" text-anchor="middle" fill="#D4A017">${cert.program || cert.course || ''}</text>
  
  <!-- 附加文本 -->
  <text x="600" y="690" font-family="Times New Roman, serif" font-size="20" text-anchor="middle" fill="#000000">${t('certificate.rightsText')}</text>
  
  <!-- 装饰元素 -->
  <path d="M350,610 C400,600 450,650 500,630 S550,600 600,630 S650,660 700,630 S750,600 800,630 S850,650 900,620" fill="none" stroke="#D4A017" stroke-width="1" opacity="0.5" />
  
  <!-- 签名区域 -->
  <text x="300" y="780" font-family="Times New Roman, serif" font-size="22" font-style="italic" text-anchor="middle" fill="#000000">Linda Foster</text>
  <line x1="200" y1="760" x2="400" y2="760" stroke="#000000" stroke-width="1" />
  <text x="300" y="800" font-family="Times New Roman, serif" font-size="16" text-anchor="middle" fill="#000000">Prof. Dr. Linda Foster</text>
  <text x="300" y="820" font-family="Times New Roman, serif" font-size="14" text-anchor="middle" fill="#000000">${t('certificate.presidentTitle')}</text>
  
  <text x="900" y="780" font-family="Times New Roman, serif" font-size="22" font-style="italic" text-anchor="middle" fill="#000000">James Carpenter</text>
  <line x1="800" y1="760" x2="1000" y2="760" stroke="#000000" stroke-width="1" />
  <text x="900" y="800" font-family="Times New Roman, serif" font-size="16" text-anchor="middle" fill="#000000">Prof. Dr. James Carpenter</text>
  <text x="900" y="820" font-family="Times New Roman, serif" font-size="14" text-anchor="middle" fill="#000000">${t('certificate.directorTitle')}</text>
  
  <!-- 认证印章 -->
  <circle cx="600" cy="750" r="50" fill="none" stroke="#D4A017" stroke-width="2" />
  <circle cx="600" cy="750" r="45" fill="none" stroke="#D4A017" stroke-width="1" />
  <text x="600" y="760" font-family="Times New Roman, serif" font-size="16" font-weight="bold" text-anchor="middle" fill="#D4A017">VERIFIED</text>
  <text x="600" y="780" font-family="Times New Roman, serif" font-size="10" text-anchor="middle" fill="#D4A017">SIU</text>
  
  <!-- 日期和证书编号 -->
  <text x="600" y="850" font-family="Times New Roman, serif" font-size="16" text-anchor="middle" fill="#000000">${t('certificate.awardedDate')}: ${formatDateEn(cert.issueDate || cert.date)}</text>
  <text x="600" y="870" font-family="Times New Roman, serif" font-size="14" text-anchor="middle" fill="#000000">${t('certificate.idLabel')}: ${cert.certificateNumber || cert.certificateId || ''}</text>
  
  <!-- 角落装饰元素 -->
  <path d="M80,80 L110,80 L110,110" fill="none" stroke="#D4A017" stroke-width="2" />
  <path d="M1120,80 L1090,80 L1090,110" fill="none" stroke="#D4A017" stroke-width="2" />
  <path d="M80,820 L110,820 L110,790" fill="none" stroke="#D4A017" stroke-width="2" />
  <path d="M1120,820 L1090,820 L1090,790" fill="none" stroke="#D4A017" stroke-width="2" />
</svg>`;
    return svg;
  }

  useEffect(() => {
    const loadCertificate = async () => {
      setLoading(true);
      setError(null);
      try {
        // 1. 获取证书数据
        const isEmbedRoute = window.location.pathname.includes('certificate-embed');
        
        let response;
        
        if (isEmbedRoute) {
          // 公共嵌入路由，使用验证API
          response = await fetch(`/api/certificates/verify/${id}`);
        } else {
          // 受保护路由，需要身份验证
          const token = localStorage.getItem('auth_token');
          if (!token) {
            throw new Error('需要身份验证才能访问证书');
          }
          
          response = await fetch(`/api/certificates/${id}`, {
            headers: {
              Authorization: `Bearer ${token}`
            }
          });
        }
        
        if (!response.ok) {
          throw new Error(`无法获取证书: ${response.statusText}`);
        }
        
        const data = await response.json();
        const cert = data.data;
        
        if (!cert) {
          throw new Error('找不到证书数据');
        }

        setCertificate(cert);

        // 2. 生成SVG
        const svgContent = await getCertificateSVG(cert);
        
        // 创建Blob和URL
        const blob = new Blob([svgContent], { type: 'image/svg+xml' });
        const processedImageUrl = URL.createObjectURL(blob);

        setCertificateSvgUrl(processedImageUrl);
      } catch (err) {
        console.error('加载证书时出错:', err);
        setError(err.message || '无法加载证书');
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      loadCertificate();
    }
    
    // 清理函数
    return () => {
      if (certificateSvgUrl) {
        URL.revokeObjectURL(certificateSvgUrl);
      }
    };
  }, [id, templateName]);

  const handleDownloadPDF = async () => {
    if (!certificate) return;
    
    // 创建隐藏容器
    let certDom = document.getElementById('certificate-html-preview');
    if (!certDom) {
      certDom = document.createElement('div');
      certDom.id = 'certificate-html-preview';
      certDom.style.position = 'absolute';
      certDom.style.left = '-9999px';
      certDom.style.top = '0';
      document.body.appendChild(certDom);
    }
    
    try {
      // 生成SVG并插入DOM
      const svgStr = await getCertificateSVG(certificate);
      certDom.innerHTML = `<div>${svgStr}</div>`;
      
      // 用html2canvas截图 - 提高分辨率(scale)以获得更清晰的PDF
      const canvas = await html2canvas(certDom, {
        scale: 4, // 提高分辨率，从3增加到4
        useCORS: true,
        backgroundColor: '#FFFDF0',
        logging: false, // 禁用日志以提高性能
        imageTimeout: 15000, // 增加图像加载超时时间
      });
      
      // 生成PDF - 增加更多配置选项
      const imgData = canvas.toDataURL('image/png', 1.0);
      const pdf = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4',
        compress: true, // 启用压缩
        precision: 16, // 提高精度
      });
      
      // 添加文档属性
      pdf.setProperties({
        title: `${certificate.recipientName || certificate.name || 'Certificate'} - ${certificate.program || certificate.course || 'Program'}`,
        subject: 'Stratford International University Certificate',
        author: 'Stratford International University',
        keywords: 'certificate, education, diploma, blockchain, verified',
        creator: 'SIU Certificate System',
      });
      
      // 添加水印文本作为安全特性
      const addWatermark = () => {
        pdf.saveGraphicsState();
        pdf.setTextColor(0, 0, 0);
        pdf.setGState(new pdf.GState({opacity: 0.05}));
        pdf.setFontSize(16);
        pdf.text('VERIFIED SIU CERTIFICATE', 40, 60, {angle: 45});
        pdf.restoreGraphicsState();
      };
      addWatermark();
      
      const imgWidth = 297; // A4纸张宽度(横向)
      const imgHeight = 210; // A4纸张高度(横向)
      
      // 添加图像并优化品质
      pdf.addImage(imgData, 'PNG', 0, 0, imgWidth, imgHeight, '', 'FAST');
      
      // 使用更好的文件命名方式，包含证书类型和日期
      const dateStr = new Date().toISOString().slice(0, 10);
      const recipientName = certificate.recipientName || certificate.name || 'Certificate';
      const safeRecipientName = recipientName.replace(/[^a-zA-Z0-9]/g, '_');
      const certId = certificate.certificateNumber || certificate._id || '';
      
      pdf.save(`SIU_Certificate_${safeRecipientName}_${certId}_${dateStr}.pdf`);
    } catch (error) {
      console.error('生成PDF时出错:', error);
      alert('下载证书时出错，请重试');
    }
  };

  return (
    <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
      <div className="px-4 sm:px-0">
        <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl">
          证书
        </h2>
      </div>

      {loading ? (
        <div className="mt-6">
          <LoadingSpinner message="正在加载证书..." />
        </div>
      ) : error ? (
        <div className="mt-6">
          <AlertMessage
            type="error"
            message={{ title: '错误', details: error }}
          />
        </div>
      ) : (
        <div className="mt-6 bg-white shadow overflow-hidden sm:rounded-lg">
          <div className="px-4 py-5 border-b border-gray-200 sm:px-6 flex justify-between items-center">
            <div>
              <h3 className="text-lg leading-6 font-medium text-gray-900">
                证书预览
              </h3>
              <p className="mt-1 max-w-2xl text-sm text-gray-500">
                您的证书已成功生成。
              </p>
            </div>
            <div className="flex space-x-4">
              <button 
                onClick={handleDownloadPDF}
                className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500"
              >
                下载PDF
              </button>
              <a
                href={certificateSvgUrl}
                download="certificate.svg"
                className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
              >
                下载SVG
              </a>
            </div>
          </div>
          <div className="certificate-preview-container p-4 flex justify-center">
            {certificateSvgUrl && (
              <div className="certificate-preview-wrapper max-w-full overflow-auto">
                <img
                  src={certificateSvgUrl}
                  alt="Certificate Preview"
                  className="certificate-preview max-w-full h-auto"
                  style={{ maxHeight: '70vh' }}
                />
              </div>
            )}
          </div>
          
          {/* 隐藏的预览区域 - 仅用于生成PDF */}
          <div
            id="certificate-html-preview"
            style={{ position: 'absolute', left: '-9999px', top: 0 }}
          />
        </div>
      )}
    </div>
  );
};

export default CertificateViewerPage;
